challenges.buggyCode:
let playerName = prompt('What is your name?');
let playerAge = prompt('How old are you?');
let rounds = prompt('How many rounds do you want to play?');

let summary = `Player: ${playerName} | Age: ${playerAge} | Rounds: ${rounds}`;
console.log(summary);

if (playerAge < 10) {
  console.log(`${playerName} is a junior player!`);
} else {
  console.log(`${playerName} is a regular player.`);
}

